// Lump 'sport' conditions under 'neuro' for the 6-category grouping
const conditionToBucket = (c) => c.cat === 'sport' ? 'neuro' : c.cat;

/* Build the 6 category cards */
const catGrid = document.getElementById('catGrid');
const catGridWrap = document.getElementById('catGridWrap');
const catSubview = document.getElementById('catSubview');
const catSubhead = document.getElementById('catSubhead');
const condGrid = document.getElementById('conditionsGrid');
const catBack = document.getElementById('catBack');
const categoryMoreWrap = document.getElementById('categoryMoreWrap');
const categoryMoreBtn = document.getElementById('categoryMoreBtn');
const conditionsMoreWrap = document.getElementById('conditionsMoreWrap');
const conditionsMoreBtn = document.getElementById('conditionsMoreBtn');
const initialCategoryCardCount = 4;
const initialConditionCardCount = 4;
let expandedCategories = false;
let expandedCategoryId = null;
let mobileConditionFlipObserver = null;

function buildConditions() {
  const isTouchDevice = window.matchMedia('(max-width: 768px)').matches || 'ontouchstart' in window;

  function clearMobileConditionObserver() {
    if (mobileConditionFlipObserver) {
      mobileConditionFlipObserver.disconnect();
      mobileConditionFlipObserver = null;
    }
  }

  function setupMobileConditionAutoFlip() {
    clearMobileConditionObserver();
    if (!isTouchDevice) return;

    const cards = Array.from(condGrid.querySelectorAll('.flip-card'));
    if (!cards.length) return;

    mobileConditionFlipObserver = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        const card = entry.target;
        const isLocked = card.dataset.userLocked === 'true';
        if (isLocked) return;

        if (entry.isIntersecting && entry.intersectionRatio >= 0.3) {
          card.classList.add('flipped');
        } else {
          card.classList.remove('flipped');
        }
      });
    }, {
      threshold: [0.18, 0.3, 0.55],
      rootMargin: '-4% 0px -8% 0px'
    });

    cards.forEach((card) => mobileConditionFlipObserver.observe(card));
  }

  function updateCategoryVisibility() {
    const cards = Array.from(catGrid.querySelectorAll('.cat-card'));
    const hasOverflow = cards.length > initialCategoryCardCount;

    cards.forEach((card, index) => {
      const shouldHide = hasOverflow && !expandedCategories && index >= initialCategoryCardCount;
      card.hidden = shouldHide;
      card.style.display = shouldHide ? 'none' : '';
    });

    if (categoryMoreWrap && categoryMoreBtn) {
      categoryMoreWrap.hidden = !hasOverflow;
      categoryMoreBtn.textContent = expandedCategories ? 'See fewer categories' : 'See more categories';
      categoryMoreBtn.setAttribute('aria-expanded', expandedCategories ? 'true' : 'false');
    }
  }

  function updateConditionVisibility() {
    const cards = Array.from(condGrid.querySelectorAll('.flip-card'));
    const hasOverflow = cards.length > initialConditionCardCount;
    const isExpanded = expandedCategoryId !== null;

    cards.forEach((card, index) => {
      const shouldHide = hasOverflow && !isExpanded && index >= initialConditionCardCount;
      card.hidden = shouldHide;
      card.style.display = shouldHide ? 'none' : '';
    });

    if (conditionsMoreWrap && conditionsMoreBtn) {
      conditionsMoreWrap.hidden = !hasOverflow;
      conditionsMoreBtn.textContent = isExpanded ? 'See fewer conditions' : 'See more conditions';
      conditionsMoreBtn.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');
    }

    setupMobileConditionAutoFlip();
  }

  categories.forEach(cat => {
    const inCat = conditions.filter(c => conditionToBucket(c) === cat.id);
    const preview = inCat.slice(0, 3).map(c => c.n).join(' · ');
    const card = document.createElement('div');
    card.className = 'cat-card';
    card.style.setProperty('--cat', cat.color);
    card.innerHTML = `
    <div style="display:flex; align-items:flex-start; gap:18px;">
      <div class="cat-icon">${cat.icon}</div>
      <div style="flex:1; min-width:0;">
        <div class="cat-count">${inCat.length} conditions</div>
        <div class="cat-title">${cat.title}</div>
      </div>
    </div>
    <div class="cat-preview"><span style="color:var(--text-body); font-weight:500;">${cat.sub}</span><br>${preview}${inCat.length > 3 ? ` <span style="color:var(--text-light);">+ ${inCat.length - 3} more</span>` : ''}</div>
    <div class="cat-cta">Tap to explore ${inCat.length} conditions <span>→</span></div>
  `;
    card.addEventListener('click', () => openCategory(cat.id));
    catGrid.appendChild(card);
  });

  updateCategoryVisibility();

  function openCategory(catId) {
    const cat = categories.find(c => c.id === catId);
    const inCat = conditions.filter(c => conditionToBucket(c) === catId);
    expandedCategoryId = null;

    catSubhead.style.setProperty('--cat', cat.color);
    catSubhead.innerHTML = `
    <div class="cat-subhead-icon" style="background: color-mix(in srgb, ${cat.color} 14%, white); color: ${cat.color};">${cat.icon}</div>
    <div>
      <div class="cat-count" style="color:${cat.color};">${inCat.length} conditions · ${cat.sub}</div>
      <h3>${cat.title}</h3>
      <p style="max-width: 720px;">${cat.desc}</p>
    </div>
  `;

    condGrid.innerHTML = '';
    inCat.forEach(c => {
      const benefits = categoryBenefits[c.cat];
      const card = document.createElement('div');
      card.className = 'flip-card';
      card.innerHTML = `
      <div class="flip-inner">
        <div class="flip-front">
          <div class="flip-front-icon">${iconFor(c.n, c.cat)}</div>
          <div class="flip-front-body">
            <div>
              <div class="flip-front-name">${c.n}</div>
              <div class="flip-front-line">${c.l}</div>
            </div>
            <div class="flip-front-cta">${isTouchDevice ? 'Tap to heal →' : 'Hover to heal →'}</div>
          </div>
        </div>
        <div class="flip-back">
          <div class="flip-back-img" style="background-image: url('${(function(){try{return poseImage(c.pose);}catch(e){return '';}}())}');">
            <div style="position:absolute; left:0; right:0; bottom:0; padding: 14px 16px; color: var(--white); font-family: 'Cormorant Garamond', serif; font-style: italic; font-size: 18px; text-align:left; z-index:2; text-shadow: 0 2px 8px rgba(0,0,0,0.7);">${c.pose}</div>
          </div>
          <div class="flip-back-body">
            <div class="flip-back-title">${c.n}</div>
            <div class="flip-back-poses">
              ${(c.poses||[c.pose]).slice(0,3).map(p=>`<span class="flip-pose-tag">${p}</span>`).join('')}
            </div>
            <div class="flip-back-meta">
              <div class="flip-meta-row"><span class="flip-meta-icon">⏱</span><span><strong>Timeline:</strong> ${c.timeline||'4–8 weeks'}</span></div>
              <div class="flip-meta-row"><span class="flip-meta-icon">✓</span><span>${c.outcome||benefits[0]}</span></div>
            </div>
            <a href="#book" class="flip-back-cta">Book Free Consultation</a>
          </div>
        </div>
      </div>
    `;
      card.addEventListener('click', (event) => {
        if (event.target.closest('a')) return;

        if (isTouchDevice) {
          const nextFlipped = !card.classList.contains('flipped');
          card.classList.toggle('flipped', nextFlipped);
          card.dataset.userLocked = nextFlipped ? 'true' : 'false';
          return;
        }

        card.classList.toggle('flipped');
      });
      condGrid.appendChild(card);
    });

    updateConditionVisibility();
    catGridWrap.classList.add('hidden');
    catSubview.classList.add('active');

    const sec = document.getElementById('conditions');
    if (sec) {
      const y = sec.getBoundingClientRect().top + window.scrollY - 80;
      window.scrollTo({ top: y, behavior: 'smooth' });
    }
  }

  catBack.addEventListener('click', () => {
    expandedCategoryId = null;
    clearMobileConditionObserver();
    if (conditionsMoreWrap) conditionsMoreWrap.hidden = true;
    catSubview.classList.remove('active');
    catGridWrap.classList.remove('hidden');
    updateCategoryVisibility();
    const sec = document.getElementById('conditions');
    if (sec) {
      const y = sec.getBoundingClientRect().top + window.scrollY - 80;
      window.scrollTo({ top: y, behavior: 'smooth' });
    }
  });

  if (categoryMoreBtn) {
    categoryMoreBtn.addEventListener('click', () => {
      expandedCategories = !expandedCategories;
      updateCategoryVisibility();
    });
  }

  if (conditionsMoreBtn) {
    conditionsMoreBtn.addEventListener('click', () => {
      if (!catSubview.classList.contains('active')) return;
      expandedCategoryId = expandedCategoryId ? null : 'expanded';
      updateConditionVisibility();
    });
  }
} // end buildConditions()

/* ============== Booking Calendar ============== */
(function() {
  const days = [];
  const today = new Date();
  for (let i = 1; i <= 7; i++) {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    if (d.getDay() === 0) continue; // skip Sunday
    days.push(d);
  }
  const slots = ['5:00 AM','6:00 AM','7:00 AM','8:00 AM','9:00 AM','10:00 AM','4:00 PM','5:00 PM','6:00 PM','7:00 PM','8:00 PM'];
  const fullSlots = []; // no slots pre-booked

  const dayNames = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

  const daysEl = document.getElementById('calDays');
  const slotsEl = document.getElementById('calSlots');
  const selectedDayInput = document.getElementById('cf-selected-day');
  const selectedSlotInput = document.getElementById('cf-selected-slot');

  if (!daysEl) return;

  days.forEach(d => {
    const btn = document.createElement('div');
    btn.className = 'cal-day';
    btn.innerHTML = `<span class="day-name">${dayNames[d.getDay()]}</span>${d.getDate()} ${monthNames[d.getMonth()]}`;
    btn.addEventListener('click', () => {
      document.querySelectorAll('.cal-day').forEach(x => x.classList.remove('selected'));
      btn.classList.add('selected');
      selectedDayInput.value = `${dayNames[d.getDay()]} ${d.getDate()} ${monthNames[d.getMonth()]}`;
    });
    daysEl.appendChild(btn);
  });

  slots.forEach(s => {
    const btn = document.createElement('div');
    btn.className = 'cal-slot' + (fullSlots.includes(s) ? ' full' : '');
    btn.textContent = s + (fullSlots.includes(s) ? ' (Full)' : '');
    if (!fullSlots.includes(s)) {
      btn.addEventListener('click', () => {
        document.querySelectorAll('.cal-slot').forEach(x => x.classList.remove('selected'));
        btn.classList.add('selected');
        selectedSlotInput.value = s;
      });
    }
    slotsEl.appendChild(btn);
  });
})();

(function() {
  'use strict';

  function setupPreviewToggle(sectionSelector, itemSelector, buttonSelector, expandLabel, collapseLabel) {
    var section = document.querySelector(sectionSelector);
    var button = document.querySelector(buttonSelector);
    if (!section || !button) return;

    var hiddenItems = section.querySelectorAll(itemSelector + '.is-collapsible');
    if (!hiddenItems.length) {
      button.style.display = 'none';
      return;
    }

    var expanded = false;

    function render() {
      hiddenItems.forEach(function(item) {
        item.classList.toggle('is-hidden-preview', !expanded);
      });
      button.textContent = expanded ? collapseLabel : expandLabel;
      button.setAttribute('aria-expanded', expanded ? 'true' : 'false');
    }

    button.addEventListener('click', function() {
      expanded = !expanded;
      render();
      if (!expanded) {
        section.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });

    render();
  }

  function initPreviewToggles() {
    setupPreviewToggle('#blog', '.blog-card', '#blogToggleBtn', 'View All Articles', 'Show Fewer Articles');
    setupPreviewToggle('#gallery', '.g-cell', '#galleryToggleBtn', 'View Full Gallery', 'Show Fewer Photos');
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initPreviewToggles);
  } else {
    initPreviewToggles();
  }
})();


/* ============== Booking Form ============== */
const consultForm = document.getElementById('consultForm');
if (consultForm) {
  consultForm.querySelectorAll('input, textarea, select').forEach(function(field) {
    field.addEventListener('focus', function() {
      document.body.classList.add('form-cursor-mode');
    });
    field.addEventListener('blur', function() {
      if (!consultForm.querySelector(':focus')) {
        document.body.classList.remove('form-cursor-mode');
      }
    });
  });

  consultForm.addEventListener('submit', function(e) {
    e.preventDefault();
    const name = document.getElementById('cf-name').value.trim();
    const phone = document.getElementById('cf-phone').value.trim();
    const condition = document.getElementById('cf-condition').value;
    const selectedDay = document.getElementById('cf-selected-day').value;
    const selectedSlot = document.getElementById('cf-selected-slot').value;
    const consent = !!(document.getElementById('cf-consent') && document.getElementById('cf-consent').checked);
    const submitBtn = consultForm.querySelector('.btn-submit');
    const successBox = document.getElementById('formSuccess');
    const formAction = (consultForm.getAttribute('action') || '').trim();
    const isWeb3Forms = /web3forms/i.test(formAction);
    if (!name || !phone || !condition || !selectedDay || !selectedSlot || !consent) {
      alert('Please fill in your name, phone number, condition, preferred day, preferred time slot, and consent before submitting.');
      return;
    }

    if (successBox) {
      successBox.style.display = 'none';
      successBox.style.background = '';
      successBox.style.borderColor = '';
      successBox.style.color = '';
    }

    if (window.location.protocol === 'file:') {
      if (successBox) {
        successBox.innerHTML = 'This local file preview cannot send the consultation email. Please test this form after deployment or on a local server.';
        successBox.style.display = 'block';
        successBox.style.background = 'rgba(255, 248, 225, 0.96)';
        successBox.style.borderColor = 'rgba(200, 149, 42, 0.32)';
        successBox.style.color = '#6b4b0f';
        successBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {
        alert('This local file preview cannot send the consultation email. Please test this form after deployment or on a local server.');
      }
      return;
    }

    if (isWeb3Forms) {
      const accessKeyField = consultForm.querySelector('input[name="access_key"]');
      const accessKey = accessKeyField ? accessKeyField.value.trim() : '';
      if (!accessKey || accessKey === 'YOUR_WEB3FORMS_ACCESS_KEY') {
        if (successBox) {
          successBox.innerHTML = 'Web3Forms is connected, but the real access key is still missing. Paste your Web3Forms access key into the form code, then test again.';
          successBox.style.display = 'block';
          successBox.style.background = 'rgba(255, 248, 225, 0.96)';
          successBox.style.borderColor = 'rgba(200, 149, 42, 0.32)';
          successBox.style.color = '#6b4b0f';
          successBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else {
          alert('Web3Forms access key is missing. Paste the real key into the form code and test again.');
        }
        return;
      }
    }

    if (submitBtn) {
      submitBtn.disabled = true;
      submitBtn.dataset.originalText = submitBtn.innerHTML;
      submitBtn.innerHTML = 'Sending Request...';
    }

    if (!isWeb3Forms) {
      if (successBox) {
        successBox.innerHTML = 'Thank you! Your consultation request has been prepared. If your form provider is connected, our team will contact you within 24 hours.';
        successBox.style.display = 'block';
        successBox.style.background = '';
        successBox.style.borderColor = '';
        successBox.style.color = '';
        successBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      HTMLFormElement.prototype.submit.call(consultForm);
      consultForm.reset();
      document.getElementById('cf-selected-day').value = '';
      document.getElementById('cf-selected-slot').value = '';
      document.querySelectorAll('.cal-day.active, .cal-slot.active').forEach(function(el) {
        el.classList.remove('active');
      });
      if (submitBtn) {
        submitBtn.disabled = false;
        submitBtn.innerHTML = submitBtn.dataset.originalText || 'Book My FREE Consultation';
      }
      return;
    }

    fetch(consultForm.action, {
      method: 'POST',
      body: new FormData(consultForm),
      headers: { Accept: 'application/json' }
    }).then(function(response) {
      if (!response.ok) {
        throw new Error('Submission failed');
      }
      return response.json();
    }).then(function() {
      consultForm.style.display = 'none';
      if (successBox) {
        successBox.innerHTML = 'Thank you! Your consultation request has been sent successfully. Our team will contact you within 24 hours.';
        successBox.style.display = 'block';
        successBox.style.background = '';
        successBox.style.borderColor = '';
        successBox.style.color = '';
        successBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
      consultForm.reset();
      document.getElementById('cf-selected-day').value = '';
      document.getElementById('cf-selected-slot').value = '';
      document.querySelectorAll('.cal-day.active, .cal-slot.active').forEach(function(el) {
        el.classList.remove('active');
      });
    }).catch(function() {
      if (successBox) {
        successBox.innerHTML = 'Your request could not be sent right now. Please try again in a moment or check that your Web3Forms access key is active.';
        successBox.style.display = 'block';
        successBox.style.background = 'rgba(255, 243, 243, 0.96)';
        successBox.style.borderColor = 'rgba(229, 62, 62, 0.2)';
        successBox.style.color = '#9b2c2c';
        successBox.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {
        alert('Your request could not be sent right now. Please try again in a moment.');
      }
    }).finally(function() {
      if (submitBtn) {
        submitBtn.disabled = false;
        submitBtn.innerHTML = submitBtn.dataset.originalText || 'Book My FREE Consultation';
      }
    });
  });
}


if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', buildConditions);
} else {
  buildConditions();
}

