/* ============== Smooth counter (cubic-ease) ============== */
function smoothCounter(el, target, suffix, duration) {
  if (!el) return;
  /* P5-4: 300ms scramble phase before actual count-up */
  var scrambleEnd = performance.now() + 300;
  function scramble(now) {
    if (now < scrambleEnd) {
      el.textContent = Math.floor(Math.random() * (target + 1)) + suffix;
      requestAnimationFrame(scramble);
    } else {
      /* hand off to real count-up */
      var start = performance.now();
      function update(time) {
        var elapsed = time - start;
        var progress = Math.min(elapsed / duration, 1);
        var eased = 1 - Math.pow(1 - progress, 3);
        el.textContent = Math.floor(eased * target) + suffix;
        if (progress < 1) requestAnimationFrame(update);
      }
      requestAnimationFrame(update);
    }
  }
  requestAnimationFrame(scramble);
}

/* ============== Reveal on scroll ============== */
const io = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      e.target.classList.add('in');
      e.target.querySelectorAll('[data-count]').forEach(el => {
        if (el.dataset.done) return;
        el.dataset.done = '1';
        const target = +el.dataset.count;
        const suffix = el.dataset.suffix || '';
        smoothCounter(el, target, suffix, 1800);
      });
    }
  });
}, { threshold: 0.15 });
document.querySelectorAll('.reveal, .reveal-stagger').forEach(el => io.observe(el));

/* ============== On-load counters (for above-fold stats) ============== */
window.addEventListener('load', () => {
  document.querySelectorAll('[data-count]').forEach(el => {
    if (el.dataset.done) return;
    el.dataset.done = '1';
    smoothCounter(el, +el.dataset.count, el.dataset.suffix || '', 2000);
  });
  /* scroll-reveal polyfill — mark visible elements immediately */
  document.querySelectorAll('.reveal-on-scroll').forEach(el => {
    const rect = el.getBoundingClientRect();
    if (rect.top < window.innerHeight) el.classList.add('visible');
  });
  window.addEventListener('scroll', () => {
    document.querySelectorAll('.reveal-on-scroll:not(.visible)').forEach(el => {
      const rect = el.getBoundingClientRect();
      if (rect.top < window.innerHeight - 60) el.classList.add('visible');
    });
  }, { passive: true });
});


(function() {
  const audio = document.getElementById('bgMusic');
  const fab   = document.getElementById('musicFab');
  if (!audio || !fab) return;

  let playing = false;
  let started = false;

  function startMusic() {
    if (started) return;
    started = true;
    audio.volume = 0.25;
    audio.play().then(() => {
      playing = true;
      fab.classList.add('playing');
      fab.textContent = '🔊';
      fab.insertAdjacentHTML('afterbegin','<span class="music-tooltip">Pause Music</span>');
    }).catch(() => {
      // Autoplay blocked — user must click manually
    });
  }

  // Try on first scroll
  window.addEventListener('scroll', startMusic, { once: true, passive: true });
  // Try on first click anywhere
  document.addEventListener('click', startMusic, { once: true });

  // Toggle on fab click
  fab.addEventListener('click', function(e) {
    e.stopPropagation();
    if (!started) { startMusic(); return; }
    if (playing) {
      audio.pause();
      playing = false;
      fab.classList.remove('playing');
      fab.innerHTML = '<span class="music-tooltip">Play Music</span>🎵';
    } else {
      audio.play();
      playing = true;
      fab.classList.add('playing');
      fab.innerHTML = '<span class="music-tooltip">Pause Music</span>🔊';
    }
  });
})();

