/* ── Gallery Lightbox ────────────────────────────────── */
(function(){
  var lb=document.getElementById('galleryLightbox');
  if(!lb)return;
  var img=document.getElementById('lbImg');
  var cap=document.getElementById('lbCaption');
  var ctr=document.getElementById('lbCounter');
  var images=[]; var cur=0;

  /* Support both legacy background-image cells and semantic <img> gallery cells */
  function collect(){
    var gallery=document.querySelector('.gallery-grid');
    if(!gallery)return;
    var cells=gallery.querySelectorAll('.g-cell');
    images=Array.from(cells).map(function(el,i){
      var imgEl=el.querySelector('img');
      if(imgEl&&imgEl.src){
        return{src:imgEl.getAttribute('src')||imgEl.src,alt:imgEl.getAttribute('alt')||el.getAttribute('data-alt')||('Gallery '+(i+1))};
      }
      var style=el.getAttribute('style')||el.style.cssText||'';
      var match=style.match(/url\(['""]?([^'""\)]+)['""]?\)/);
      var alt=el.getAttribute('data-alt')||('Gallery '+(i+1));
      return{src:match?match[1]:'',alt:alt};
    }).filter(function(x){return x.src&&x.src.length>4});
    cells.forEach(function(el,i){
      el.style.cursor='zoom-in';
      (function(idx){
        el.addEventListener('click',function(e){e.stopPropagation();openLB(idx)});
      })(i);
    });
  }

  function openLB(i){
    if(!images.length)collect();
    if(!images.length)return;
    cur=i; show();
    lb.classList.add('active');
    document.body.style.overflow='hidden';
  }
  function closeLB(){lb.classList.remove('active');document.body.style.overflow=''}
  function show(){
    if(!images[cur])return;
    img.src=images[cur].src;
    cap.textContent=images[cur].alt;
    ctr.textContent=(cur+1)+' / '+images.length;
  }
  function prev(){cur=(cur-1+images.length)%images.length;show()}
  function next(){cur=(cur+1)%images.length;show()}

  document.getElementById('lbClose').addEventListener('click',closeLB);
  document.getElementById('lbPrev').addEventListener('click',prev);
  document.getElementById('lbNext').addEventListener('click',next);
  lb.addEventListener('click',function(e){if(e.target===lb)closeLB()});
  document.addEventListener('keydown',function(e){
    if(!lb.classList.contains('active'))return;
    if(e.key==='ArrowLeft')prev();
    if(e.key==='ArrowRight')next();
    if(e.key==='Escape')closeLB();
  });
  window.openGalleryLightbox=function(){collect();openLB(0)};
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',collect)}else{collect()}
})();

