(function() {

  /* ══ HERO PARTICLES ══ */
  var hCanvas = document.getElementById('heroParticles');
  if (hCanvas) {
    var hCtx = hCanvas.getContext('2d');
    var hW = hCanvas.width  = hCanvas.offsetWidth  || window.innerWidth;
    var hH = hCanvas.height = hCanvas.offsetHeight || 600;
    var hParts = [];
    /* Spawn 40 gentle floating particles */
    for (var i = 0; i < 18; i++) {
      hParts.push({
        x: Math.random() * hW,
        y: Math.random() * hH,
        r: .8 + Math.random() * 2.5,
        vx: (Math.random()-.5) * .35,
        vy: -.2 - Math.random() * .4,
        alpha: .1 + Math.random() * .35,
        color: Math.random() > .5 ? '#E5B842' : '#fff'
      });
    }
    var hFrame = 0;
    (function animHero() {
      requestAnimationFrame(animHero);
      hFrame++;
      if (hFrame % 3 !== 0) return; /* draw every 3rd frame — ~20fps, invisible to eye */
      hCtx.clearRect(0, 0, hW, hH);
      hParts.forEach(function(p) {
        p.x += p.vx * 3; p.y += p.vy * 3;
        if (p.y < -5) { p.y = hH + 5; p.x = Math.random() * hW; }
        if (p.x < -5) p.x = hW + 5;
        if (p.x > hW + 5) p.x = -5;
        hCtx.beginPath();
        hCtx.arc(p.x, p.y, p.r, 0, Math.PI*2);
        hCtx.fillStyle = p.color;
        hCtx.globalAlpha = p.alpha;
        hCtx.fill();
      });
      hCtx.globalAlpha = 1;
    })();
  }

  /* ══ CONDITIONS CARDS — IntersectionObserver with stagger ══ */
  var io = window.IntersectionObserver;
  var condSection = document.querySelector('.conditions');
  if (condSection && io) {
    var cards = condSection.querySelectorAll('.flip-card');

    new IntersectionObserver(function(entries, obs) {
      if (!entries[0].isIntersecting) return;
      obs.unobserve(condSection);
      cards.forEach(function(card, i) {
        setTimeout(function() {
          card.classList.add('card-vis');
        }, i * 110);
      });
    }, { threshold: 0.08 }).observe(condSection);

    /* tilt removed — pure CSS hover handles this below */
  }

  /* ══ HERO — ensure badge + CTA stagger in on load ══ */
  window.addEventListener('load', function() {
    var els = [
      '.hero-badge', '.hero-eyebrow', '.hero-tagline',
      '.hero-sub', '.hero-cta', '.hero .btn'
    ];
    els.forEach(function(sel, i) {
      document.querySelectorAll(sel).forEach(function(el) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(22px)';
        el.style.transition = 'opacity .7s ease, transform .7s cubic-bezier(.16,1,.3,1)';
        el.style.transitionDelay = (0.2 + i * 0.12) + 's';
        setTimeout(function() {
          el.style.opacity = '1';
          el.style.transform = 'translateY(0)';
        }, (200 + i * 120));
      });
    });
  });

})();

