(function(){
  var targets = [1200, 40, 15];
  var duration = 2200;
  window.addEventListener('load', function(){
    var els = document.querySelectorAll('.hero-mini-stat .stat-num');
    setTimeout(function(){
      els.forEach(function(el, i){
        var t = targets[i];
        var s = performance.now();
        (function run(now){
          var p  = Math.min((now - s) / duration, 1);
          var e  = 1 - Math.pow(1 - p, 3);
          var v  = Math.floor(e * t);
          /* comma-format thousands */
          var d  = t >= 1000
            ? Math.floor(v / 1000) + ',' + String(v % 1000).padStart(3, '0')
            : String(v);
          el.innerHTML = d + '<sup>+</sup>';
          if (p < 1) requestAnimationFrame(run);
          else el.innerHTML = (t >= 1000 ? '1,200' : t) + '<sup>+</sup>';
        })(s);
      });
    }, 700);
  });
})();

/* ═══ PHASE 2 — PERFORMANCE OPTIMISATIONS ════════════════════════════
   1. will-change only on mouseenter / remove on mouseleave
   2. _heroVisible flag — sparkle/particle loops check this
   3. orbSpin removal (pure GPU waste on decorative elements)
═══════════════════════════════════════════════════════════════════════ */
(function(){
  'use strict';

  /* 1. will-change: activate GPU layer only when element is about to animate */
  var WC = '.btn,.btn-primary,.btn-gold,.cta-btn,.flip-card,.tl-card,.testimonial-card,.pricing-card,.how-card,.cat-card,.blog-card';
  function setupWC(){
    document.querySelectorAll(WC).forEach(function(el){
      el.addEventListener('mouseenter',function(){ this.style.willChange='transform'; });
      el.addEventListener('mouseleave',function(){ this.style.willChange='auto'; });
    });
  }

  /* 2. Hero visibility flag for RAF loops */
  window._heroVisible = true;
  function setupHeroObserver(){
    var hero = document.querySelector('.hero, #hero, section.hero');
    if(hero && 'IntersectionObserver' in window){
      new IntersectionObserver(function(entries){
        window._heroVisible = entries[0].isIntersecting;
      },{threshold:0.05}).observe(hero);
    }
  }

  /* 3. Patch spawn functions so they respect the flag */
  function patchSpawn(){
    ['spawnSparkle','spawnParticle','addParticle'].forEach(function(name){
      if(typeof window[name]==='function'){
        var orig = window[name];
        window[name] = function(){
          if(!window._heroVisible) return;
          return orig.apply(this, arguments);
        };
      }
    });
  }

  /* 4. Remove orbSpin — pure rotation with no content value, wastes compositor */
  function fixOrbs(){
    document.querySelectorAll('[class*="orb"]').forEach(function(el){
      var a = (window.getComputedStyle(el).animationName||'');
      if(a.indexOf('orbSpin')!==-1){
        el.style.animation = a.split(',').filter(function(p){ return p.indexOf('orbSpin')===-1; }).join(',');
      }
    });
  }

  function init(){
    setupWC();
    setupHeroObserver();
    patchSpawn();
    setTimeout(fixOrbs, 600);
  }

  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded', init);
  } else { init(); }
})();



